1|#!/usr/bin/env node
  2|/**
  3| * OpenCTI MCP Server
  4| *
  5| * Provides Claude Code with tools to query OpenCTI threat intelligence:
  6| * - search-indicators: Search threat indicators (IOCs)
  7| * - get-indicator: Get indicator details and relationships
  8| * - search-reports: Search threat intelligence reports
  9| * - get-attack-patterns: List MITRE ATT&CK techniques
 10| * - enrich-observable: Request enrichment for an observable
 11| * - get-relationships: Get entity relationships
 12| *
 13| * Auth: OpenCTI API token in Authorization header.
 14| * Environment: OPENCTI_URL, OPENCTI_TOKEN
 15| */
 16|
 17|import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
 18|import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
 19|import { z } from "zod";
 20|
 21|const OPENCTI_URL = process.env.OPENCTI_URL || "https://localhost:4000";
 22|const OPENCTI_TOKEN = process.env.OPENCTI_TOKEN;
 23|
 24|if (!OPENCTI_TOKEN) {
 25|  console.error("FATAL: OPENCTI_TOKEN environment variable is required");
 26|  process.exit(1);
 27|}
 28|
 29|const REQUEST_TIMEOUT_MS = 10_000;
 30|/** Validate ID parameters to prevent path traversal */
 31|const safeId = z.string().regex(/^[a-zA-Z0-9_-]+$/, "Invalid ID format");
 32|
 33|/** Execute a GraphQL query against OpenCTI with timeout */
 34|async function graphql(query: string, variables: Record<string, unknown> = {}): Promise<unknown> {
 35|  const controller = new AbortController();
 36|  const timer = setTimeout(() => controller.abort(), REQUEST_TIMEOUT_MS);
 37|
 38|  try {
 39|    const resp = await fetch(`${OPENCTI_URL}/graphql`, {
 40|      method: "POST",
 41|      headers: {
 42|        Authorization: `Bearer ${OPENCTI_TOKEN}`,
 43|        "Content-Type": "application/json",
 44|      },
 45|      body: JSON.stringify({ query, variables }),
 46|      signal: controller.signal,
 47|    });
 48|
 49|    if (!resp.ok) {
 50|      const text = (await resp.text()).slice(0, 200);
 51|      throw new Error(`OpenCTI API error: ${resp.status} ${text}`);
 52|    }
 53|
 54|    const result = await resp.json() as { data: unknown; errors?

 55|    if (result.errors) {
 56|      throw new Error(`GraphQL errors: ${JSON.stringify(result.errors).slice(0, 500)}`);
 57|    }
 58|    return result.data;
 59|  } finally {
 60|    clearTimeout(timer);
 61|  }
 62|}
 63|
 64|/** Maximum response size in characters to prevent excessive output to LLM */
 65|const MAX_RESPONSE_CHARS = 50_000;
 66|
 67|/** Serialize data to JSON and truncate if it exceeds the size limit */
 68|function formatResponse(data: unknown): string {
 69|  const json = JSON.stringify(data, null, 2);
 70|  if (json.length <= MAX_RESPONSE_CHARS) return json;
 71|  return json.slice(0, MAX_RESPONSE_CHARS) + `\n... [truncated: ${json.length} chars total, showing first ${MAX_RESPONSE_CHARS}]`;
 72|}
 73|
 74|const server = new McpServer({
 75|  name: "opencti-mcp",
 76|  version: "1.0.0",
 77|});
 78|
 79|// search-indicators
 80|server.tool(
 81|  "search-indicators",
 82|  "Search OpenCTI threat indicators (IOCs) by value or type",
 83|  {
 84|    value: z.string().optional().describe("Search by indicator value (IP, domain, hash, etc.)"),
 85|    type: z.string().optional().describe("Filter by type (IPv4-Addr, Domain-Name, StixFile, Url, etc.)"),
 86|    limit: z.number().min(1).max(100).optional().default(20),
 87|  },
 88|  async ({ value, type, limit }) => {
 89|    const filters = [];
 90|    if (type) {
 91|      filters.push({ key: "entity_type", values: [type] });
 92|    }
 93|
 94|    const result = await graphql(
 95|      `query SearchIndicators($search: String, $first: Int, $filters: FilterGroup) {
 96|        stixCyberObservables(search: $search, first: $first, filters: $filters) {
 97|          edges {
 98|            node {
 99|              id
100|              entity_type
101|              observable_value
102|              created_at
103|              updated_at
104|              objectLabel { value color }
105|              createdBy { name }
106|              objectMarking { definition }
107|            }
108|          }
109|          pageInfo { globalCount }
110|        }
111|      }`,
112|      {
113|        search: value || null,
114|        first: limit,
115|        filters: filters.length > 0
116|          ? { mode: "and", filters, filterGroups: [] }
117|          : null,
118|      }
119|    );
120|    return { content: [{ type: "text" as const, text: formatResponse(result) }] };
121|  }
122|);
123|
124|// get-indicator
125|server.tool(
126|  "get-indicator",
127|  "Get full details of an OpenCTI indicator including relationships",
128|  { indicator_id: safeId.describe("OpenCTI entity ID") },
129|  async ({ indicator_id }) => {
130|    const result = await graphql(
131|      `query GetIndicator($id: String!)

132|        stixCyberObservable(id: $id) {
133|          id
134|          entity_type
135|          observable_value
136|          created_at
137|          updated_at
138|          objectLabel { value color }
139|          createdBy { name }
140|          objectMarking { definition }
141|          stixCoreRelationships {
142|            edges {
143|              node {
144|                id
145|                relationship_type
146|                from { ... on StixDomainObject { id name entity_type } }
147|                to { ... on StixDomainObject { id name entity_type } }
148|              }
149|            }
150|          }
151|          indicators {
152|            edges {
153|              node {
154|                id
155|                name
156|                pattern
157|                valid_from
158|                valid_until
159|              }
160|            }
161|          }
162|        }
163|      }`,
164|      { id: indicator_id }
165|    );
166|    return { content: [{ type: "text" as const, text: formatResponse(result) }] };
167|  }
168|);
169|
170|// search-reports
171|server.tool(
172|  "search-reports",
173|  "Search OpenCTI threat intelligence reports",
174|  {
175|    search: z.string().max(256).optional().describe("Search text in report names/descriptions"),
176|    limit: z.number().min(1).max(100).optional().default(10),
177|  },
178|  async ({ search, limit }) => {
179|    const result = await graphql(
180|      `query SearchReports($search: String, $first: Int) {
181|        reports(search: $search, first: $first, orderBy: created_at, orderMode: desc) {
182|          edges {
183|            node {
184|              id
185|              name
186|              description
187|              published
188|              created_at
189|              report_types
190|              objectLabel { value }
191|              createdBy { name }
192|              objectMarking { definition }
193|            }
194|          }
195|          pageInfo { globalCount }
196|        }
197|      }`,
198|      { search: search || null, first: limit }
199|    );
200|    return { content: [{ type: "text" as const, text: formatResponse(result) }] };
201|  }
202|);
203|
204|// get-attack-patterns
205|server.tool(
206|  "get-attack-patterns",
207|  "List MITRE ATT&CK techniques, optionally filtered by tactic",
208|  {
209|    search: z.string().max(256).optional().describe("Search text (e.g., 'phishing', 'lateral movement')"),
210|    tactic: z.string().max(256).optional().describe("Filter by kill chain phase (e.g., 'initial-access', 'lateral-movement')"),
211|    limit: z.number().min(1).max(100).optional().default(20),
212|  },
213|  async ({ search, tactic, limit }) => {
214|    const result = await graphql(
215|      `query GetAttackPatterns($search: String, $first: Int) {
216|        attackPatterns(search: $search, first: $first, orderBy: name, orderMode: asc) {
217|          edges {
218|            node {
219|              id
220|              name
221|              description
222|              x_mitre_id
223|              x_mitre_platforms
224|              killChainPhases { kill_chain_name phase_name }
225|              subAttackPatterns {
226|                edges { node { id name x_mitre_id } }
227|              }
228|            }
229|          }
230|          pageInfo { globalCount }
231|        }
232|      }`,
233|      { search: search || tactic || null, first: limit }
234|    );
235|    return { content: [{ type: "text" as const, text: formatResponse(result) }] };
236|  }
237|);
238|
239|// enrich-observable
240|server.tool(
241|  "enrich-observable",
242|  "[WRITE] Request enrichment for an observable in OpenCTI. This triggers external connector queries.

243|  {
244|    observable_id: safeId.describe("Observable entity ID to enrich"),
245|    connector_id: safeId.optional().describe("Specific connector ID to use"),
246|  },
247|  async ({ observable_id, connector_id }) => {
248|    const result = await graphql(
249|      `mutation EnrichObservable($id: ID!, $connectorId: ID) {
250|        stixCyberObservableEdit(id: $id) {
251|          askEnrichment(connectorId: $connectorId) {
252|            id
253|            connector { name }
254|            status
255|          }
256|        }
257|      }`,
258|      { id: observable_id, connectorId: connector_id || null }
259|    );
260|    return { content: [{ type: "text" as const, text: formatResponse(result) }] };
261|  }
262|);
263|
264|// get-relationships
265|server.tool(
266|  "get-relationships",
267|  "Get relationships for an OpenCTI entity",
268|  {
269|    entity_id: safeId.describe("Entity ID to get relationships for"),
270|    relationship_type: z.string().max(100).optional().describe("Filter by type (e.g., 'uses', 'targets', 'indicates')"),
271|    limit: z.number().min(1).max(100).optional().default(20),
272|  },
273|  async ({ entity_id, relationship_type, limit }) => {
274|    const result = await graphql(
275|      `query GetRelationships($id: String!, $relationship_type: [String], $first: Int) {
276|        stixCoreRelationships(
277|          fromOrToId: $id,
278|          relationship_type: $relationship_type,
279|          first: $first,
280|          orderBy: created_at,
281|          orderMode: desc
282|        ) {
283|          edges {
284|            node {
285|              id
286|              relationship_type
287|              description
288|              confidence
289|              start_time
290|              stop_time
291|              from {
292|                ... on StixDomainObject { id name entity_type }
293|                ... on StixCyberObservable { id observable_value entity_type }
294|              }
295|              to {
296|                ... on StixDomainObject { id name entity_type }
297|                ... on StixCyberObservable { id observable_value entity_type }
298|              }
299|            }
300|          }
301|          pageInfo { globalCount }
302|        }
303|      }`,
304|      {
305|        id: entity_id,
306|        relationship_type: relationship_type ? [relationship_type] : null,
307|        first: limit,
308|      }
309|    );
310|    return { content: [{ type: "text" as const, text: formatResponse(result) }] };
311|  }
312|);
313|
314|// --- Start Server ---
315|async function main() {
316|  // Connectivity test
317|  try {
318|    const controller = new AbortController();
319|    const timer = setTimeout(() => controller.abort(), 5_000);
320|    const resp = await fetch(`${OPENCTI_URL}/health`, {
321|      headers: { Authorization: `Bearer ${OPENCTI_TOKEN}` },
322|      signal: controller.signal,
323|    }).finally(() => clearTimeout(timer));
324|    console.error(`OpenCTI connectivity: ${resp.ok ? "OK" : resp.status} (${OPENCTI_URL})`);
325|  } catch (e) {
326|    console.error(`WARNING: OpenCTI unreachable at ${OPENCTI_URL} — tools will fail until it's available`);
327|  }
328|
329|  const transport = new StdioServerTransport();
330|  await server.connect(transport);
331|  console.error("OpenCTI MCP server running on stdio");
332|}
333|
334|main().catch((err) => {
335|  console.error("Fatal:", err.message);
336|  process.exit(1);
337|});
