1|#!/usr/bin/env node
  2|/**
  3| * TheHive MCP Server
  4| *
  5| * Provides Claude Code with tools to manage TheHive incident response:
  6| * - list-cases: List open/recent cases
  7| * - create-case: Create a new incident case
  8| * - get-case: Get case details with observables
  9| * - add-observable: Add an IOC to a case
 10| * - run-analyzer: Run Cortex analyzer on an observable
 11| * - get-analyzer-report: Get analyzer results
 12| * - search-alerts: Search alerts forwarded from Wazuh
 13| * - merge-alerts: Merge related alerts into a case
 14| *
 15| * Auth: TheHive API key in Authorization header.
 16| * Environment: THEHIVE_URL, THEHIVE_API_KEY
 17| */
 18|
 19|import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
 20|import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
 21|import { z } from "zod";
 22|
 23|const THEHIVE_URL = process.env.THEHIVE_URL || "https://localhost:9000";
 24|const THEHIVE_API_KEY = process.env.THEHIVE_API_KEY;
 25|
 26|if (!THEHIVE_API_KEY) {
 27|  console.error("FATAL: THEHIVE_API_KEY environment variable is required");
 28|  process.exit(1);
 29|}
 30|
 31|const REQUEST_TIMEOUT_MS = 10_000;
 32|/** Validate ID parameters to prevent path traversal */
 33|const safeId = z.string().regex(/^[~a-zA-Z0-9_.-]+$/, "Invalid ID format");
 34|
 35|/** Make authenticated API call to TheHive with timeout */
 36|async function thehiveApi(
 37|  method: string,
 38|  path: string,
 39|  body?: unknown
 40|): Promise<unknown> {
 41|  const controller = new AbortController();
 42|  const timer = setTimeout(() => controller.abort(), REQUEST_TIMEOUT_MS);
 43|
 44|  try {
 45|    const url = new URL(path, THEHIVE_URL);
 46|    const resp = await fetch(url.toString(), {
 47|      method,
 48|      headers: {
 49|        Authorization: `Bearer ${THEHIVE_API_KEY}`,
 50|        "Content-Type": "application/json",
 51|      },
 52|      body: body ?

 53|      signal: controller.signal,
 54|    });
 55|
 56|    if (!resp.ok) {
 57|      const text = (await resp.text()).slice(0, 200);
 58|      throw new Error(`TheHive API error: ${resp.status} ${text}`);
 59|    }
 60|    return resp.json();
 61|  } finally {
 62|    clearTimeout(timer);
 63|  }
 64|}
 65|
 66|/** Maximum response size in characters to prevent excessive output to LLM */
 67|const MAX_RESPONSE_CHARS = 50_000;
 68|
 69|/** Serialize data to JSON and truncate if it exceeds the size limit */
 70|function formatResponse(data: unknown): string {
 71|  const json = JSON.stringify(data, null, 2);
 72|  if (json.length <= MAX_RESPONSE_CHARS) return json;
 73|  return json.slice(0, MAX_RESPONSE_CHARS) + `\n... [truncated: ${json.length} chars total, showing first ${MAX_RESPONSE_CHARS}]`;
 74|}
 75|
 76|const server = new McpServer({
 77|  name: "thehive-mcp",
 78|  version: "1.0.0",
 79|});
 80|
 81|// list-cases
 82|server.tool(
 83|  "list-cases",
 84|  "List TheHive incident response cases",
 85|  {
 86|    status: z.enum(["Open", "Resolved", "Deleted"]).optional().default("Open"),
 87|    severity: z.number().min(1).max(4).optional().describe("1=Low, 2=Medium, 3=High, 4=Critical"),
 88|    limit: z.number().min(1).max(100).optional().default(20),
 89|  },
 90|  async ({ status, severity, limit }) => {
 91|    const query: Record<string, unknown>[] = [];
 92|    if (status) query.push({ _name: "filter", _field: "status", _value: status });
 93|    if (severity) query.push({ _name: "filter", _field: "severity", _value: severity });
 94|    query.push({ _name: "sort", _fields: [{ _field: "createdAt", _order: "desc" }] });
 95|    query.push({ _name: "page", from: 0, to: limit });
 96|
 97|    const result = await thehiveApi("POST", "/api/v1/query", { query });
 98|    return { content: [{ type: "text" as const, text: formatResponse(result) }] };
 99|  }
100|);
101|
102|// create-case
103|server.tool(
104|  "create-case",
105|  "[WRITE] Create a new TheHive incident case. This creates a persistent record.

106|  {
107|    title: z.string().max(500).describe("Case title"),
108|    description: z.string().max(10000).describe("Case description (markdown supported)"),
109|    severity: z.number().min(1).max(4).default(2).describe("1=Low, 2=Medium, 3=High, 4=Critical"),
110|    tags: z.array(z.string()).optional().default([]),
111|  },
112|  async ({ title, description, severity, tags }) => {
113|    const result = await thehiveApi("POST", "/api/v1/case", {
114|      title,
115|      description,
116|      severity,
117|      tags,
118|      flag: false,
119|      tlp: 2,  // TLP:AMBER
120|      pap: 2,  // PAP:AMBER
121|    });
122|    return { content: [{ type: "text" as const, text: formatResponse(result) }] };
123|  }
124|);
125|
126|// get-case
127|server.tool(
128|  "get-case",
129|  "Get TheHive case details including observables and tasks",
130|  { case_id: safeId.describe("Case ID (e.g., '~123')") },
131|  async ({ case_id }) => {
132|    const caseData = await thehiveApi("GET", `/api/v1/case/${encodeURIComponent(case_id)}`);
133|    // Also fetch observables for this case
134|    const observables = await thehiveApi("POST", "/api/v1/query", {
135|      query: [
136|        { _name: "getCase", idOrName: case_id },
137|        { _name: "observables" },
138|        { _name: "sort", _fields: [{ _field: "createdAt", _order: "desc" }] },
139|      ],
140|    });
141|    return {
142|      content: [{
143|        type: "text" as const,
144|        text: formatResponse({ case: caseData, observables }),
145|      }],
146|    };
147|  }
148|);
149|
150|// add-observable
151|server.tool(
152|  "add-observable",
153|  "[WRITE] Add an observable (IOC) to a TheHive case. This modifies case data.",
154|  {
155|    case_id: safeId.describe("Case ID"),
156|    data_type: z.enum(["ip", "domain", "url", "hash", "filename", "mail", "other"]),
157|    data: z.string().max(2048).describe("Observable value (e.g., IP address, domain name)"),
158|    tags: z.array(z.string().max(100)).max(20).optional().default([]),
159|    message: z.string().max(2048).optional().describe("Context about this observable"),
160|  },
161|  async ({ case_id, data_type, data, tags, message }) => {
162|    const result = await thehiveApi("POST", `/api/v1/case/${encodeURIComponent(case_id)}/observable`, {
163|      dataType: data_type,
164|      data,
165|      tags,
166|      message: message || "",
167|      tlp: 2,
168|      pap: 2,
169|      ioc: true,
170|    });
171|    return { content: [{ type: "text" as const, text: formatResponse(result) }] };
172|  }
173|);
