199|    return { content: [{ type: "text" as const, text: formatResponse(result) }] };
200|  }
201|);
202|
203|// search-alerts
204|server.tool(
205|  "search-alerts",
206|  "Search TheHive alerts (e.g., from Wazuh integration)",
207|  {
208|    source: z.string().max(256).optional().describe("Alert source filter (e.g., 'Wazuh')"),
209|    severity: z.number().min(1).max(4).optional(),
210|    limit: z.number().min(1).max(100).optional().default(20),
211|  },
212|  async ({ source, severity, limit }) => {
213|    const query: Record<string, unknown>[] = [];
214|    if (source) query.push({ _name: "filter", _field: "source", _value: source });
215|    if (severity) query.push({ _name: "filter", _field: "severity", _value: severity });
216|    query.push({ _name: "sort", _fields: [{ _field: "createdAt", _order: "desc" }] });
217|    query.push({ _name: "page", from: 0, to: limit });
218|
219|    const result = await thehiveApi("POST", "/api/v1/query", { query });
220|    return { content: [{ type: "text" as const, text: formatResponse(result) }] };
221|  }
222|);
223|
224|// merge-alerts
225|server.tool(
226|  "merge-alerts",
227|  "[WRITE] Merge related TheHive alerts into a single case. This permanently combines alerts.",
228|  {
229|    alert_ids: z.array(safeId).describe("Alert IDs to merge"),
230|    case_id: safeId.optional().describe("Existing case ID to merge into (creates new if omitted)"),
231|  },
232|  async ({ alert_ids, case_id }) => {
233|    const result = await thehiveApi("POST", "/api/v1/alert/merge", {
234|      alertIds: alert_ids,
235|      caseId: case_id,
236|    });
237|    return { content: [{ type: "text" as const, text: formatResponse(result) }] };
238|  }
