248|      headers: { Authorization: `Bearer ${THEHIVE_API_KEY}` },
249|      signal: controller.signal,
250|    }).finally(() => clearTimeout(timer));
251|    console.error(`TheHive connectivity: ${resp.ok ?

252|  } catch (e) {
253|    console.error(`WARNING: TheHive unreachable at ${THEHIVE_URL} — tools will fail until it's available`);
254|  }
255|
256|  const transport = new StdioServerTransport();
257|  await server.connect(transport);
258|  console.error("TheHive MCP server running on stdio");
259|}
