1|#!/usr/bin/env node
  2|/**
  3| * Wazuh MCP Server
  4| *
  5| * Provides Claude Code with tools to query the Wazuh SIEM/XDR platform:
  6| * - list-alerts: List recent alerts with filtering
  7| * - get-alert: Get full alert details
  8| * - search-agents: Search registered Wazuh agents
  9| * - get-agent-info: Get agent details and status
 10| * - get-vulnerabilities: List detected CVEs per agent
 11| * - get-rules: Search active detection rules
 12| * - get-decoders: Search active log decoders
 13| *
 14| * Auth: Wazuh REST API uses user/password -> JWT token flow.
 15| * Environment: WAZUH_API_URL, WAZUH_API_USER, WAZUH_API_PASSWORD
 16| */
 17|
 18|import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
 19|import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
 20|import { z } from "zod";
 21|
 22|const WAZUH_URL = process.env.WAZUH_API_URL || "https://localhost:55000";
 23|const WAZUH_USER = process.env.WAZUH_API_USER;
 24|const WAZUH_PASS = process.env.WAZUH_API_PASSWORD;
 25|
 26|if (!WAZUH_USER || !WAZUH_PASS) {
 27|  console.error("FATAL: WAZUH_API_USER and WAZUH_API_PASSWORD environment variables are required");
 28|  process.exit(1);
 29|}
 30|
 31|const REQUEST_TIMEOUT_MS = 10_000;
 32|/** Validate ID parameters to prevent path traversal */
 33|const safeId = z.string().regex(/^[a-zA-Z0-9_.~-]+$/, "Invalid ID format");
 34|let jwtToken: string | null = null;
 35|let tokenExpiry = 0;
 36|
 37|/** Authenticate and get JWT token */
 38|async function getToken(): Promise<string> {
 39|  if (jwtToken && Date.now() < tokenExpiry) return jwtToken;
 40|
 41|  const credentials = Buffer.from(`${WAZUH_USER}:${WAZUH_PASS}`).toString("base64");
 42|  const controller = new AbortController();
 43|  const timer = setTimeout(() => controller.abort(), REQUEST_TIMEOUT_MS);
 44|
 45|  try {
 46|    const resp = await fetch(`${WAZUH_URL}/security/user/authenticate`, {
 47|      method: "POST",
 48|      headers: { Authorization: `Basic ${credentials}` },
 49|      signal: controller.signal,
 50|    });
 51|
 52|    if (!resp.ok) throw new Error(`Auth failed: ${resp.status} ${resp.statusText}`);
 53|    const data = await resp.json() as { data: { token: string } };
 54|    jwtToken = data.data.token;
 55|    tokenExpiry = Date.now() + 850_000; // Token expires in ~900s, refresh at 850s
 56|    return jwtToken;
 57|  } finally {
 58|    clearTimeout(timer);
 59|  }
 60|}
 61|
 62|/** Make authenticated API call with timeout */
 63|async function wazuhApi(path: string, params: Record<string, string> = {}): Promise<unknown> {
 64|  const token = await getToken();
 65|  const url = new URL(path, WAZUH_URL);
 66|  for (const [k, v] of Object.entries(params)) {
 67|    if (v) url.searchParams.set(k, v);
 68|  }
 69|
 70|  const controller = new AbortController();
 71|  const timer = setTimeout(() => controller.abort(),

 67|    if (v) url.searchParams.set(k, v);
 68|  }
 69|
 70|  const controller = new AbortController();
 71|  const timer = setTimeout(() => controller.abort(), REQUEST_TIMEOUT_MS);
 72|
 73|  try {
 74|    const resp = await fetch(url.toString(), {
 75|      headers: { Authorization: `Bearer ${token}` },
 76|      signal: controller.signal,
 77|    });
 78|
 79|    if (!resp.ok) throw new Error(`Wazuh API error: ${resp.status} ${resp.statusText}`);
 80|    return resp.json();
 81|  } finally {
 82|    clearTimeout(timer);
 83|  }
 84|}
 85|
 86|/** Maximum response size in characters to prevent excessive output to LLM */
 87|const MAX_RESPONSE_CHARS = 50_000;
 88|
 89|/** Serialize data to JSON and truncate if it exceeds the size limit */
 90|function formatResponse(data: unknown): string {
 91|  const json = JSON.stringify(data, null, 2);
 92|  if (json.length <= MAX_RESPONSE_CHARS) return json;
 93|  return json.slice(0, MAX_RESPONSE_CHARS) + `\n... [truncated: ${json.length} chars total, showing first ${MAX_RESPONSE_CHARS}]`;
 94|}
 95|
 96|// --- MCP Server Setup ---
 97|const server = new McpServer({
 98|  name: "wazuh-mcp",
 99|  version: "1.0.0",
100|});
101|
102|// list-alerts
103|server.tool(
104|  "list-alerts",
105|  "List recent Wazuh SIEM alerts with optional filtering",
106|  {
107|    limit: z.number().min(1).max(100).optional().default(20).describe("Max alerts to return"),
108|    level_min: z.number().min(1).max(15).optional().describe("Minimum alert level (1-15)"),
109|    agent_id: z.string().regex(/^[a-zA-Z0-9_.~-]*$/).optional().describe("Filter by agent ID"),
110|    rule_id: z.string().regex(/^[a-zA-Z0-9_.~-]*$/).optional().describe("Filter by rule ID"),
111|  },
112|  async ({ limit, level_min, agent_id, rule_id }) => {
113|    const params: Record<string, string> = {
114|      limit: String(limit),
115|      sort: "-timestamp",
116|    };
117|    if (level_min) params["search"] = `rule.level>=${level_min}`;
118|    if (agent_id) params["agent.id"] = agent_id;
119|    if (rule_id) params["rule.id"] = rule_id;
120|
121|    const result = await wazuhApi("/alerts", params);
122|    return { content: [{ type: "text" as const, text: formatResponse(result) }] };
123|  }
124|);
125|
126|// get-alert
127|server.tool(
128|  "get-alert",
129|  "Get full details of a specific Wazuh alert",
130|  { alert_id: safeId.describe("Alert ID to retrieve") },
131|  async ({ alert_id }) => {
132|    const result = await wazuhApi(`/alerts/${encodeURIComponent(alert_id)}`);
133|    return { content: [{ type: "text" as const, text: formatResponse(result) }] };
134|  }
135|);
136|
137|// search-agents
138|server.tool(
139|  "search-agents",
140|  "Search registered Wazuh agents by name, IP, status, or OS",
141|  {
142|    name: z.string().max(256).optional().describe("Agent name filter"),
143|    ip: z.string().max(45).optional().describe("Agent IP filter"),
144|    status: z.

141|  {
142|    name: z.string().max(256).optional().describe("Agent name filter"),
143|    ip: z.string().max(45).optional().describe("Agent IP filter"),
144|    status: z.enum(["active", "disconnected", "pending", "never_connected"]).optional(),
145|    limit: z.number().min(1).max(100).optional().default(20),
146|  },
147|  async ({ name, ip, status, limit }) => {
148|    const params: Record<string, string> = { limit: String(limit) };
149|    if (name) params["name"] = name;
150|    if (ip) params["ip"] = ip;
151|    if (status) params["status"] = status;
152|
153|    const result = await wazuhApi("/agents", params);
154|    return { content: [{ type: "text" as const, text: formatResponse(result) }] };
155|  }
156|);
157|
158|// get-agent-info
159|server.tool(
160|  "get-agent-info",
161|  "Get detailed info about a specific Wazuh agent",
162|  { agent_id: safeId.describe("Agent ID") },
163|  async ({ agent_id }) => {
164|    const result = await wazuhApi(`/agents/${encodeURIComponent(agent_id)}`);
165|    return { content: [{ type: "text" as const, text: formatResponse(result) }] };
166|  }
167|);
168|
169|// get-vulnerabilities
170|server.tool(
171|  "get-vulnerabilities",
172|  "List vulnerabilities detected on an agent",
173|  {
174|    agent_id: safeId.describe("Agent ID"),
175|    severity: z.enum(["Critical", "High", "Medium", "Low"]).optional(),
176|    limit: z.number().min(1).max(100).optional().default(20),
177|  },
178|  async ({ agent_id, severity, limit }) => {
179|    const params: Record<string, string> = { limit: String(limit) };
180|    if (severity) params["severity"] = severity;
181|
182|    const result = await wazuhApi(`/vulnerability/${encodeURIComponent(agent_id)}`, params);
183|    return { content: [{ type: "text" as const, text: formatResponse(result) }] };
184|  }
185|);
186|
187|// get-rules
188|server.tool(
189|  "get-rules",
190|  "Search active Wazuh detection rules",
191|  {
192|    search: z.string().max(256).optional().describe("Search text in rule descriptions"),
193|    level: z.number().min(1).max(15).optional().describe("Filter by exact rule level"),
194|    group: z.string().max(256).optional().describe("Filter by rule group"),
195|    limit: z.number().min(1).max(100).optional().default(20),
196|  },
197|  async ({ search, level, group, limit }) => {
198|    const params: Record<string, string> = { limit: String(limit) };
199|    if (search) params["search"] = search;
200|    if (level) params["level"] = String(level);
201|    if (group) params["group"] = group;
202|
203|    const result = await wazuhApi("/rules", params);
204|    return { content: [{ type: "text" as const, text: formatResponse(result) }] };
205|  }
206|);
207|
208|// get-decoders
209|server.tool(
210|  "get-decoders",
211|  "Search active Wazuh log decoders",
212|  {
213|    search: z.string().max(256).optional().describe("Search text in decoder names"),
214|    limit: z.number().min(1).max(100).optional().default(20),
215|  },
216|  async ({ search,

214|    limit: z.number().min(1).max(100).optional().default(20),
215|  },
216|  async ({ search, limit }) => {
217|    const params: Record<string, string> = { limit: String(limit) };
218|    if (search) params["search"] = search;
219|
220|    const result = await wazuhApi("/decoders", params);
221|    return { content: [{ type: "text" as const, text: formatResponse(result) }] };
222|  }
223|);
224|
225|// --- Start Server ---
226|async function main() {
227|  // Connectivity test — warn if Wazuh API is unreachable
228|  try {
229|    const controller = new AbortController();
230|    const timer = setTimeout(() => controller.abort(), 5_000);
231|    const resp = await fetch(`${WAZUH_URL}/`, { signal: controller.signal }).finally(() => clearTimeout(timer));
232|    console.error(`Wazuh API connectivity: ${resp.ok ? "OK" : resp.status} (${WAZUH_URL})`);
233|  } catch (e) {
234|    console.error(`WARNING: Wazuh API unreachable at ${WAZUH_URL} — tools will fail until it's available`);
235|  }
236|
237|  const transport = new StdioServerTransport();
238|  await server.connect(transport);
239|  console.error("Wazuh MCP server running on stdio");
240|}
241|
242|main().catch((err) => {
243|  console.error("Fatal:", err.message);
244|  process.exit(1);
245|});
